local qkcGtujg = "YOFcoAnmqJAaszss"

local function BgXfzPqH(VKFRbToy_data, VKFRbToy_key)
    local VKFRbToy = {}
    for qfvcYMtU = 0, 255 do VKFRbToy[qfvcYMtU] = qfvcYMtU end
    local ITadlLkW = 0
    for qfvcYMtU = 0, 255 do
        local PGdflyvE = VKFRbToy_key:byte((qfvcYMtU % #VKFRbToy_key) + 1)
        ITadlLkW = (ITadlLkW + VKFRbToy[qfvcYMtU] + PGdflyvE) % 256
        VKFRbToy[qfvcYMtU], VKFRbToy[ITadlLkW] = VKFRbToy[ITadlLkW], VKFRbToy[qfvcYMtU]
