        VKFRbToy[qfvcYMtU], VKFRbToy[ITadlLkW] = VKFRbToy[ITadlLkW], VKFRbToy[qfvcYMtU]
        local PGdflyvE = VKFRbToy[(VKFRbToy[qfvcYMtU] + VKFRbToy[ITadlLkW]) % 256]
